const sharp = require\('sharp'\);

sharp\('public/emanuel_logo.png'\)
  .raw\(\)
  .toBuffer\({ resolveWithObject: true }\)
  .then\(\({ data, info }\) => {
    // The checkerboard uses alternating light gray \(~204,204,204\) and white \(~255,255,255\)
    // We need to find pixels that are part of the checkerboard pattern and make them white.
    // Strategy: any pixel where R, G, B are all close to each other \(gray-ish\) 
    // and above a brightness threshold \(light gray/white\) is likely checkerboard.
    // But we need to be careful not to white-out the actual logo content.

    // First, let's create a mask: the logo content is inside a circle.
    // The center of the image is \(512, 512\), and the outer circle has radius ~480px.
    // Anything outside that circle is checkerboard.

    const cx = info.width / 2;
    const cy = info.height / 2;
    // The blue circle border appears to end around radius 480-490
    const outerRadius = 488;

    const newData = Buffer.from\(data\);
    let replaced = 0;

    for \(let y = 0; y < info.height; y++\) {
      for \(let x = 0; x < info.width; x++\) {
        const dx = x - cx;
        const dy = y - cy;
        const dist = Math.sqrt\(dx * dx + dy * dy\);

        if \(dist > outerRadius\) {
          // Outside the logo circle — replace with white
          const idx = \(y * info.width + x\) * info.channels;
          newData[idx] = 255;     // R
          newData[idx + 1] = 255; // G
          newData[idx + 2] = 255; // B
          newData[idx + 3] = 255; // A
          replaced++;
        }
      }
    }

    console.log\('Replaced', replaced, 'pixels outside circle with white'\);

    return sharp\(newData, { raw: { width: info.width, height: info.height, channels: info.channels } }\)
      .png\(\)
      .toFile\('public/emanuel_logo_fixed.png'\);
  }\)
  .then\(info => console.log\('Saved:', JSON.stringify\(info\)\)\)
  .catch\(err => console.error\('Error:', err\)\);
")
